-- 1. Create puzzle_attempts table
CREATE TABLE IF NOT EXISTS public.puzzle_attempts (
  id              UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id         UUID        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  puzzle_id       UUID        NOT NULL REFERENCES public.puzzles(id) ON DELETE CASCADE,
  solved          BOOLEAN     NOT NULL DEFAULT false,
  hints_used      INTEGER     NOT NULL DEFAULT 0,
  attempts_count  INTEGER     NOT NULL DEFAULT 1,
  time_spent_secs INTEGER,
  completed_at    TIMESTAMPTZ,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (user_id, puzzle_id)
);

CREATE INDEX IF NOT EXISTS idx_puzzle_attempts_user   ON public.puzzle_attempts (user_id);
CREATE INDEX IF NOT EXISTS idx_puzzle_attempts_puzzle ON public.puzzle_attempts (puzzle_id);
CREATE INDEX IF NOT EXISTS idx_puzzle_attempts_solved ON public.puzzle_attempts (user_id, solved);

ALTER TABLE public.puzzle_attempts ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own puzzle attempts"
  ON public.puzzle_attempts FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own puzzle attempts"
  ON public.puzzle_attempts FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own puzzle attempts"
  ON public.puzzle_attempts FOR UPDATE USING (auth.uid() = user_id);

-- 2. Add puzzle_rating to profiles
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS puzzle_rating INTEGER NOT NULL DEFAULT 1200;

